@namespace Lumeo

<a class="@CssClass" @attributes="AllAttributes">@ChildContent</a>

@code {
    /// <summary>The URL the link navigates to. Omitted from the rendered <c>&lt;a&gt;</c>
    /// entirely (no <c>href</c> attribute) when null, empty, or whitespace-only, so the
    /// link stays inert instead of navigating to the current page.</summary>
    [Parameter] public string? Href { get; set; }
    /// <summary>Opens the link in a new tab (<c>target="_blank"</c>), automatically adding
    /// <c>rel="noopener noreferrer"</c> unless the caller already supplied <c>rel</c>.</summary>
    [Parameter] public bool External { get; set; }

    /// <summary>
    /// Renders the link as non-interactive: no <c>href</c>, <c>aria-disabled="true"</c>,
    /// <c>tabindex="-1"</c> (removed from the tab order) and pointer events disabled.
    /// </summary>
    [Parameter] public bool Disabled { get; set; }

    /// <summary>
    /// Value for the <c>aria-current</c> attribute when this link represents the
    /// current item (e.g. <c>"page"</c> for the active nav link). Null omits it.
    /// </summary>
    [Parameter] public string? AriaCurrent { get; set; }

    /// <summary>Visual style: <c>"default"</c> (primary color, underline on hover),
    /// <c>"muted"</c> (muted color, foreground on hover), or <c>"underline"</c>
    /// (always underlined).</summary>
    [Parameter] public string Variant { get; set; } = "default";
    /// <summary>Text size utility suffix (e.g. <c>"sm"</c> renders <c>text-sm</c>). Omitted
    /// when null, leaving the inherited font size.</summary>
    [Parameter] public string? Size { get; set; }
    /// <summary>The link's visible content.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }
    /// <summary>Additional CSS classes merged onto the <c>&lt;a&gt;</c> element.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Unmatched attributes splatted onto the <c>&lt;a&gt;</c> element.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private Dictionary<string, object> AllAttributes
    {
        get
        {
            var attrs = AdditionalAttributes != null
                ? new Dictionary<string, object>(AdditionalAttributes)
                : new Dictionary<string, object>();

            // aria-current is independent of interactivity: a disabled link can
            // still be the current page, so emit it before the Disabled early
            // return (otherwise the current-page indicator is silently lost).
            if (!string.IsNullOrEmpty(AriaCurrent))
            {
                attrs["aria-current"] = AriaCurrent;
            }

            if (Disabled)
            {
                // A disabled link is inert: drop href so it can't navigate, and
                // remove it from the tab order. pointer-events are killed via CSS.
                attrs.Remove("href");
                attrs["aria-disabled"] = "true";
                attrs["tabindex"] = "-1";
                return attrs;
            }

            // href: only emit when we actually have one. Rendering href="" (the
            // old behaviour for Href=null) makes the anchor navigate to the
            // current page root rather than being inert. Whitespace-only Href is
            // treated the same as null/empty so it can't reintroduce that bug.
            if (!string.IsNullOrWhiteSpace(Href))
            {
                attrs["href"] = Href;
            }

            if (External)
            {
                attrs["target"] = "_blank";
            }

            // rel-safety: any link that opens in a new browsing context
            // (target=_blank, whether set via External or AdditionalAttributes)
            // needs rel="noopener noreferrer" to close the reverse-tabnabbing
            // hole. Respect a caller-supplied rel if present.
            if (attrs.TryGetValue("target", out var target)
                && string.Equals(target?.ToString(), "_blank", StringComparison.OrdinalIgnoreCase)
                && !attrs.ContainsKey("rel"))
            {
                attrs["rel"] = "noopener noreferrer";
            }

            return attrs;
        }
    }

    private string VariantClasses => Variant switch
    {
        "muted" => "text-muted-foreground hover:text-foreground",
        "underline" => "underline underline-offset-4",
        _ => "text-primary underline-offset-4 hover:underline"
    };

    private string CssClass => Cx.Join(
        VariantClasses,
        Cx.When(!string.IsNullOrEmpty(Size), $"text-{Size}"),
        Cx.When(Disabled, "pointer-events-none opacity-50"),
        Class);
}
